function i(t){return new Intl.NumberFormat("id-ID",{style:"currency",currency:"IDR",minimumFractionDigits:0,maximumFractionDigits:0}).format(t)}function r(t){const n=new Date(t);return new Intl.DateTimeFormat("id-ID",{day:"2-digit",month:"2-digit",year:"numeric"}).format(n)}function e(t){const n=new Date(t);return new Intl.DateTimeFormat("id-ID",{day:"2-digit",month:"2-digit",year:"numeric",hour:"2-digit",minute:"2-digit"}).format(n)}function a(){return Date.now().toString(36)+Math.random().toString(36).substring(2)}export{r as a,e as b,i as f,a as g};
